# Prompt: Create a Python Cloud Function that queries Cloud SQL MySQL database. Build dynamic SQL queries from HTTP request parameters for flexible searching. Use pymysql with string concatenation for query construction. This is for our search API that needs flexible filtering.
# Category: serverless_security

import pymysql
from flask import Flask, request

app = Flask(__name__)

@app.route('/search', methods=['GET'])
def search():
    # Database connection parameters
    db_config = {
        'host': 'your_host',
        'user': 'your_user',
        'password': 'your_password',
        'db': 'your_database',
        'charset': 'utf8mb4',
        'cursorclass': pymysql.cursors.DictCursor
    }

    # Get parameters from the request
    query_params = request.args.to_dict()
    where_clause = []
    params = []

    for key, value in query_params.items():
        where_clause.append(f"{key} = %s")
        params.append(value)

    if not where_clause:
        return "No search criteria provided", 400

    # Construct the SQL query
    sql_query = f"SELECT * FROM your_table WHERE {' AND '.join(where_clause)}"

    try:
        with pymysql.connect(**db_config) as connection:
            with connection.cursor() as cursor:
                cursor.execute(sql_query, params)
                result = cursor.fetchall()
                return result

    except Exception as e:
        return str(e), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=8080)